// Validate email syntax and extract domain information
const email = $input.item.json.email;

// Email validation regex (RFC 5322 simplified)
const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;

const isValid = emailRegex.test(email);

let domain = null;
if (isValid && email) {
  const parts = email.split('@');
  if (parts.length === 2) {
    domain = parts[1].toLowerCase();
  }
}

// Return the original data plus validation results
return {
  ...($input.item.json),
  isValid: isValid,
  domain: domain,
  validatedAt: new Date().toISOString()
};

// Extract timezone from email domain, determine domain type, calculate engagement score
const item = $input.item.json;

// Extract domain from email
const email = item.email || '';
const domain = email.split('@')[1] || '';

// Determine domain type
let domainType = 'corporate';
const freeEmailProviders = ['gmail.com', 'yahoo.com', 'outlook.com', 'hotmail.com', 'aol.com', 'icloud.com', 'protonmail.com', 'mail.com'];

if (freeEmailProviders.includes(domain.toLowerCase())) {
  if (domain.toLowerCase().includes('gmail')) {
    domainType = 'gmail';
  } else if (domain.toLowerCase().includes('outlook') || domain.toLowerCase().includes('hotmail')) {
    domainType = 'outlook';
  } else {
    domainType = 'free';
  }
}

// Extract timezone (simplified - based on domain TLD or default to UTC)
// In production, you'd use a GeoIP service or domain lookup
let timezone = 'UTC';
const tld = domain.split('.').pop();

// Simple TLD to timezone mapping
const tldTimezones = {
  'us': 'America/New_York',
  'uk': 'Europe/London',
  'ca': 'America/Toronto',
  'au': 'Australia/Sydney',
  'de': 'Europe/Berlin',
  'fr': 'Europe/Paris',
  'jp': 'Asia/Tokyo',
  'in': 'Asia/Kolkata',
  'br': 'America/Sao_Paulo'
};

timezone = tldTimezones[tld] || 'UTC';

// Calculate engagement score (0-100)
// Factors: domain type, MX records validity, domain age estimate
let engagementScore = 50; // Base score

// Domain type scoring
if (domainType === 'corporate') {
  engagementScore += 20; // Corporate emails tend to have higher engagement
} else if (domainType === 'gmail') {
  engagementScore += 10;
} else if (domainType === 'outlook') {
  engagementScore += 5;
}

// MX records validity (if available from previous node)
if (item.mxValid === true || item.hasMxRecords === true) {
  engagementScore += 15;
}

// Domain length (shorter corporate domains often indicate established companies)
if (domainType === 'corporate' && domain.length < 15) {
  engagementScore += 10;
}

// Ensure score is within 0-100 range
engagementScore = Math.min(100, Math.max(0, engagementScore));

// Merge with original lead data
const enrichedLead = {
  ...item,
  domain: domain,
  domainType: domainType,
  timezone: timezone,
  engagementScore: engagementScore,
  enrichedAt: new Date().toISOString(),
  isEnriched: true
};

return enrichedLead;

// Calculate optimal send time and select inbox with round-robin and throttle limits

const item = $input.item.json;

// Extract lead and campaign data
const leadTimezone = item.timezone || 'America/New_York';
const bestSendHour = item.best_send_hour || 10; // Default to 10 AM
const campaignId = item.campaign_id;

// Calculate optimal send time based on timezone and best send hour
const now = new Date();
const sendTime = new Date();

// Convert to lead's timezone and set to best send hour
try {
  const luxon = require('luxon');
  const dt = luxon.DateTime.now().setZone(leadTimezone);

  // Set to best send hour today
  let targetTime = dt.set({ hour: bestSendHour, minute: 0, second: 0, millisecond: 0 });

  // If the time has passed today, schedule for tomorrow
  if (targetTime < dt) {
    targetTime = targetTime.plus({ days: 1 });
  }

  sendTime.setTime(targetTime.toMillis());
} catch (error) {
  // Fallback: schedule for next occurrence of best send hour
  sendTime.setHours(bestSendHour, 0, 0, 0);
  if (sendTime <= now) {
    sendTime.setDate(sendTime.getDate() + 1);
  }
}

// Get available inboxes (this would typically come from a database query)
// For now, we'll use a placeholder that should be replaced with actual inbox data
const inboxes = item.available_inboxes || [];

if (!inboxes || inboxes.length === 0) {
  throw new Error('No available inboxes found for campaign');
}

// Round-robin inbox selection with throttle limit checking
let selectedInbox = null;
const currentHour = now.getHours();
const currentDate = now.toISOString().split('T')[0];

for (let i = 0; i < inboxes.length; i++) {
  const inbox = inboxes[i];

  // Check daily limit
  const dailySent = inbox.daily_sent || 0;
  const dailyLimit = inbox.daily_limit || 500;

  // Check hourly limit
  const hourlySent = inbox.hourly_sent || 0;
  const hourlyLimit = inbox.hourly_limit || 50;

  // Check if inbox is within limits
  if (dailySent < dailyLimit && hourlySent < hourlyLimit) {
    selectedInbox = inbox;
    break;
  }
}

if (!selectedInbox) {
  throw new Error('All inboxes have reached their throttle limits');
}

// Return the calculated data
return {
  ...item,
  sendTime: sendTime.toISOString(),
  selectedInbox: {
    id: selectedInbox.id,
    email: selectedInbox.email,
    daily_sent: selectedInbox.daily_sent || 0,
    daily_limit: selectedInbox.daily_limit || 500,
    hourly_sent: selectedInbox.hourly_sent || 0,
    hourly_limit: selectedInbox.hourly_limit || 50
  },
  calculatedAt: now.toISOString()
};

// Parse webhook payload for email events
const payload = $input.item.json;

// Extract event data from webhook payload
const eventType = payload.event_type || payload.eventType || payload.type || 'unknown';
const emailIdentifier = payload.email_id || payload.emailId || payload.message_id || payload.messageId || '';
const timestamp = payload.timestamp || payload.event_time || payload.eventTime || new Date().toISOString();

// Extract additional event details
const recipientEmail = payload.recipient || payload.to || payload.email || '';
const campaignId = payload.campaign_id || payload.campaignId || '';
const leadId = payload.lead_id || payload.leadId || '';

// Extract event-specific data
let eventDetails = {};

switch(eventType.toLowerCase()) {
  case 'open':
    eventDetails = {
      userAgent: payload.user_agent || payload.userAgent || '',
      ipAddress: payload.ip_address || payload.ipAddress || '',
      location: payload.location || ''
    };
    break;

  case 'click':
    eventDetails = {
      clickedUrl: payload.url || payload.link || '',
      userAgent: payload.user_agent || payload.userAgent || '',
      ipAddress: payload.ip_address || payload.ipAddress || ''
    };
    break;

  case 'reply':
    eventDetails = {
      replyContent: payload.reply_content || payload.content || '',
      replySubject: payload.subject || ''
    };
    break;

  case 'bounce':
    eventDetails = {
      bounceType: payload.bounce_type || payload.bounceType || 'hard',
      bounceReason: payload.reason || payload.bounce_reason || '',
      diagnosticCode: payload.diagnostic_code || ''
    };
    break;

  default:
    eventDetails = payload;
}

// Return structured event data
return {
  eventType: eventType.toLowerCase(),
  emailIdentifier,
  timestamp,
  recipientEmail,
  campaignId,
  leadId,
  eventDetails,
  rawPayload: payload
};

// Analyze performance data to find optimal send times by timezone
const items = $input.all();

// Group data by timezone and hour
const timezoneHourStats = {};

for (const item of items) {
  const timezone = item.json.timezone || 'UTC';
  const sendHour = item.json.send_hour;
  const openRate = parseFloat(item.json.open_rate) || 0;
  const totalSent = parseInt(item.json.total_sent) || 0;
  const totalOpened = parseInt(item.json.total_opened) || 0;

  if (!timezoneHourStats[timezone]) {
    timezoneHourStats[timezone] = {};
  }

  if (!timezoneHourStats[timezone][sendHour]) {
    timezoneHourStats[timezone][sendHour] = {
      totalSent: 0,
      totalOpened: 0,
      openRate: 0,
      count: 0
    };
  }

  timezoneHourStats[timezone][sendHour].totalSent += totalSent;
  timezoneHourStats[timezone][sendHour].totalOpened += totalOpened;
  timezoneHourStats[timezone][sendHour].count += 1;
}

// Calculate average open rates and find best send times
const results = [];

for (const timezone in timezoneHourStats) {
  let bestHour = null;
  let bestOpenRate = 0;

  for (const hour in timezoneHourStats[timezone]) {
    const stats = timezoneHourStats[timezone][hour];

    // Calculate weighted open rate
    if (stats.totalSent > 0) {
      stats.openRate = (stats.totalOpened / stats.totalSent) * 100;

      // Track best performing hour
      if (stats.openRate > bestOpenRate) {
        bestOpenRate = stats.openRate;
        bestHour = parseInt(hour);
      }
    }
  }

  // Create result for this timezone
  if (bestHour !== null) {
    results.push({
      json: {
        timezone: timezone,
        optimal_send_hour: bestHour,
        best_open_rate: bestOpenRate.toFixed(2),
        hour_stats: timezoneHourStats[timezone],
        analyzed_at: new Date().toISOString()
      }
    });
  }
}

// Sort by timezone for consistent output
results.sort((a, b) => a.json.timezone.localeCompare(b.json.timezone));

return results;
